{"content": "1|// Token server to recieve, route tokens, and output total acquired tokens.
2|
3|use futures_util::{SinkExt, StreamExt};
4|use std::collections::HashMap;
5|use std::sync::atomic::{AtomicU64, AtomicU32, Ordering};
6|use std::sync::Arc;
7|use tokio::net::{TcpListener, TcpStream};
8|use tokio::sync::{mpsc, Mutex};
9|use tokio_tungstenite::{accept_async, tungstenite::Message};
10|
11|const PORT: u16 = 8080;
12|const PROXIES_LIST_LENGTH: u32 = 250;
13|
14|type Tx = mpsc::UnboundedSender<Message>;
15|
16|#[derive(Debug)]
17|struct ReceiverEntry {
18|    tx: Tx,
19|    acquired_tokens: usize
20|}
21|
22|#[derive(Debug, Default)]
23|struct State {
24|    receivers: HashMap<u64, ReceiverEntry>
25|}
26|
27|static NEXT_ID: AtomicU64 = AtomicU64::new(0);
28|static TOTAL_TOKENS_COUNT: AtomicU64 = AtomicU64::new(0);
29|static SOLVER_IDX: AtomicU32 = AtomicU32::new(0);
30|
31|#[tokio::main]
32|async fn main() {
33|    let addr = format!("0.0.0.0:{}", PORT);
34|    let listener = TcpListener::bind(&addr).await.expect("Failed to bind");
35|    println!("WebSocket server listening on ws://localhost:{}", PORT);
36|
37|    let state: Arc<Mutex<State>> = Arc::new(Mutex::new(State::default()));
38|
39|    while let Ok((stream, _)) = listener.accept().await {
40|        let state = Arc::clone(&state);
41|        tokio::spawn(handle_connection(stream, state));
42|    }
43|}
44|
45|async fn handle_connection(stream: TcpStream, state: Arc<Mutex<State>>) {
46|    let ws_stream = match accept_async(stream).await {
47|        Ok(ws) => ws,
48|        Err(e) => {
49|            eprintln!("[-] WebSocket handshake failed: {}", e);
50|            return;
51|        }
52|    };
53|
54|    let id = NEXT_ID.fetch_add(1, Ordering::Relaxed);
55|    let (mut ws_tx, mut ws_rx) = ws_stream.split();
56|
57|    let (tx, mut rx) = mpsc::unbounded_channel::<Message>();
58|
59|    tokio::spawn(async move {
60|        while let Some(msg) = rx.recv().await {
61|            if ws_tx.send(msg).await.is_err() {
62|                break;
63|            }
64|        }
65|    });
66|
67|    while let Some(result) = ws_rx.next().await {
68|        let raw = match result {
69|            Ok(Message::Binary(data)) => data,
70|            Ok(Message::Close(_)) | Err(_) => break,
71|            _ => continue,
72|        };
73|
74|        if raw.is_empty() {
75|            continue;
76|        }
77|
78|        let header = raw[0];
79|
80|        match header {
81|            // Incoming token from a sender, which we route to the receiver with least amount of acquired tokens.
82|            // [0, ...solver_idx_bytes, ...token_bytes]
83|            0 => {
84|                TOTAL_TOKENS_COUNT.fetch_add(1, Ordering::Relaxed);
85|
86|                let solver_idx_and_token_bytes = &raw[1..];
87|
88|                // [...solver_idx_bytes, ...token_bytes].
89|                let mut token_packet = Vec::with_capacity(solver_idx_and_token_bytes.len());
90|                token_packet.extend_from_slice(solver_idx_and_token_bytes);
91|
92|                let mut s = state.lock().await;
93|
94|                // Find the receiver with the least acquired tokens.
95|                let best = s.receivers.iter().min_by_key(|(_, entry)| entry.acquired_tokens).map(|(k, _)| *k);
96|
97|                if let Some(recv_id) = best {
98|                    println!("sending new token to socket with ID: {}", recv_id);
99|                    if let Some(entry) = s.receivers.get_mut(&recv_id) {
100|                        let _ = entry.tx.send(Message::Binary(token_packet));
101|                        entry.acquired_tokens += 1;
102|                    }
103|                } else {
104|                    eprintln!("[-] No receivers available to route token to");
105|                }
106|            }
107|
108|            // Register this socket as a receiver.
109|            // [1]
110|            1 => {
111|                let mut s = state.lock().await;
112|                s.receivers.insert(id, ReceiverEntry { tx: tx.clone(), acquired_tokens: 0 });
113|                println!("[+] Set new receiver. Total recievers: {}", s.receivers.len());
114|            }
115|
116|            // Token count request. Send total acquired tokens back to requester.
117|            // [2]
118|            2 => {
119|                let mut total_tokens_packet = Vec::new();
120|                total_tokens_packet.extend_from_slice(&TOTAL_TOKENS_COUNT.load(Ordering::Relaxed).to_le_bytes());
121|                let _ = tx.send(Message::binary(total_tokens_packet));
122|                println!("[+] Total tokens count request packet recieved. Sent back the total tokens count.");
123|            }
124|
125|            // Solver idx request packet. Used by solvers to know which proxy index they're working with. Also increments and modulos the idx for next time it is accessed.
126|            // [3]
127|            3 => {
128|                let mut solver_idx_packet = Vec::new();
129|                let solver_idx = SOLVER_IDX.fetch_add(1, Ordering::Relaxed) % PROXIES_LIST_LENGTH;
130|                solver_idx_packet.extend_from_slice(&solver_idx.to_le_bytes());
131|                let _ = tx.send(Message::binary(solver_idx_packet));
132|                println!("[+] Solver idx request packet recieved. Sending back solver idx: {}.", solver_idx);
133|            }
134|
135|            _ => {
136|                eprintln!("Unknown header byte: {}", header);
137|            }
138|        }
139|    }
140|
141|    let mut s = state.lock().await;
142|    s.receivers.remove(&id);
143|}
