{"content": "1|// Cloudflare turnstile checkbox clicker. 
2|
3|use std::{
4|    collections::VecDeque,
5|    sync::atomic::{AtomicBool, Ordering},
6|    sync::Arc,
7|    thread,
8|    time::Duration,
9|};
10|
11|use enigo::{Button, Coordinate, Enigo, Mouse, Settings};
12|use inputbot::KeybdKey;
13|use screenshots::Screen;
14|use rand::Rng;
15|
16|// Some config to aid with detection.
17|
18|// Minimum area of the interior checkbox rect.
19|const MIN_INTERIOR_AREA: u32 = 200;
20|// Maximum area of the interior checkbox rect.
21|const MAX_INTERIOR_AREA: u32 = 200000;
22|// Border color greyscale target. For example, 74 -> RGB(74, 74, 74) is the target color for the checkbox border.
23|const BORDER_TARGET: u8 = 74;
24|// Border tolerance to ensure it can still be detected.
25|const BORDER_TOLERANCE: u8 = 30;
26|// The maximum variance between R, G, and B fields, this ensures we maintain greyscale.
27|const BORDER_BALANCE: u8 = 20;
28|// Minimum amount of connected pixels detected within our previous greyscale config parameters that can be used to declare a checkbox border.
29|const MIN_BORDER_PIXELS: usize = 50;
30|
31|#[derive(Debug, Clone)]
32|pub struct Rect {
33|    pub x: u32,
34|    pub y: u32,
35|    pub width: u32,
36|    pub height: u32,
37|}
38|
39|fn main() {
40|    let active = Arc::new(AtomicBool::new(false));
41|    let active_clone = Arc::clone(&active);
42|
43|    // Press "F8" to toggle the scanner on/off for safety.
44|    KeybdKey::F8Key.bind(move || {
45|        let was = active_clone.fetch_xor(true, Ordering::SeqCst);
46|        println!(
47|            "Auto-clicker has been {}",
48|            if !was { "ACTIVATED." } else { "PAUSED." }
49|        );
50|    });
51|
52|    // Inputbot's event loop must run on its own thread.
53|    thread::spawn(|| inputbot::handle_input_events());
54|
55|    let mut enigo = Enigo::new(&Settings::default()).expect("Failed to create Enigo");
56|
57|    println!("Press F8 to activate the auto-clicker.");
58|
59|    loop {
60|        if !active.load(Ordering::SeqCst) {
61|            thread::sleep(Duration::from_millis(50));
62|            continue;
63|        }
64|
65|        let queue = detect_checkboxes();
66|        println!("Detected {} checkbox(es)", queue.len());
67|
68|        for rect in &queue {
69|            // If active is false, the toggle will just stop us from clicking anything--but it'll still keep detecting checkboxes.
70|            if !active.load(Ordering::SeqCst) { break };
71|
72|            // Set random click points and click.
73|            let mut rand = rand::thread_rng();
74|            let click_x = rect.x + (rect.width as f32 * rand.gen::<f32>()) as u32;
75|            let click_y = rect.y + (rect.height as f32 * rand.gen::<f32>()) as u32;
76|
77|            enigo.move_mouse(click_x as i32, click_y as i32, Coordinate::Abs).expect("move_mouse failed");
78|            enigo.button(Button::Left, enigo::Direction::Click).expect("click failed");
79|
80|            thread::sleep(Duration::from_millis(50));
81|        }
82|
83|        thread::sleep(Duration::from_millis(250));
84|    }
85|}
86|
87|pub fn detect_checkboxes() -> VecDeque<Rect> {
88|    let mut queue = VecDeque::new();
89|
90|    let screens = match Screen::all() {
91|        Ok(s) => s,
92|        Err(e) => { eprintln!("Screen::all failed: {e}"); return queue },
93|    };
94|
95|    for screen in screens {
96|        let image = match screen.capture() {
97|            Ok(img) => img,
98|            Err(e) => { eprintln!("capture failed: {e}"); continue },
99|        };
100|
101|        let width = image.width();
102|        let height = image.height();
103|        let mut visited = vec![false; (width * height) as usize];
104|
105|        for y in 0..height {
106|            for x in 0..width {
107|                let idx = (y * width + x) as usize;
108|                if visited[idx] { continue };
109|
110|                // Continue searching for a border color pixel.
111|                if !is_border(*image.get_pixel(x, y)) { continue };
112|
113|                // If we find a border pixel, attempt to identify a connected ring, 
114|                // and check if the total pixel count is less than the min border pixels.
115|                let (count, outer) = find_border_outline(&image, &mut visited, x, y, width, height);
116|
117|                if count < MIN_BORDER_PIXELS { continue };
118|
119|                // Once we've found our border identify the interior from such, and do some checks.
120|                let Some(interior) = find_interior(&image, &outer) else { continue };
121|
122|                // Ensure the interior area isn't too large.
123|                let area = interior.width * interior.height;
124|                if area < MIN_INTERIOR_AREA || area > MAX_INTERIOR_AREA { continue };
125|
126|                queue.push_back(interior);
127|            }
128|        }
129|    }
130|
131|    queue
132|}
133|
134|// Check if our given RGB color matches a border pixel based on the limitations set within our config.
135|fn is_border(p: image::Rgba<u8>) -> bool {
136|    let (r, g, b) = (p[0], p[1], p[2]);
137|    let near = |ch: u8| (ch as i16 - BORDER_TARGET as i16).unsigned_abs() <= BORDER_TOLERANCE as u16;
138|    if !near(r) || !near(g) || !near(b) { return false };
139|    let spread = r.max(g).max(b) - r.min(g).min(b);
140|    spread <= BORDER_BALANCE
141|}
142|
143|// Solves for and identifies the border outline and pixels by continually branching out and searching for connected border pixels,
144|// in a DFS until the path either ends or all pixels have been visited (reconnects).
145|fn find_border_outline(
146|    image: &image::RgbaImage,
147|    visited: &mut [bool],
148|    start_x: u32,
149|    start_y: u32,
150|    width: u32,
151|    height: u32,
152|) -> (usize, Rect) {
153|    let mut stack = vec![(start_x, start_y)];
154|    let mut count = 0;
155|    let mut min_x = start_x;
156|    let mut min_y = start_y;
157|    let mut max_x = start_x;
158|    let mut max_y = start_y;
159|
160|    // Pop off each grey pixel
161|    while let Some((x, y)) = stack.pop() {
162|        if x >= width || y >= height { continue };
163|        let idx = (y * width + x) as usize;
164|        // If already visited (ring completed or turned back) OR it's not a border pixel anymore (thus not connected),
165|        // Then quit skip out.
166|        if visited[idx] || !is_border(*image.get_pixel(x, y)) { continue };
167|
168|        visited[idx] = true;
169|        count += 1;
170|
171|        min_x = min_x.min(x);
172|        max_x = max_x.max(x);
173|        min_y = min_y.min(y);
174|        max_y = max_y.max(y);
175|
176|        // Push out children in each of the four directions for new branches to test the closed loop.
177|        if x > 0 { stack.push((x - 1, y)) };
178|        if x + 1 < width { stack.push((x + 1, y)) };
179|        if y > 0 { stack.push((x, y - 1)) };
180|        if y + 1 < height { stack.push((x, y + 1)) };
181|    }
182|
183|    (count, Rect { x: min_x, y: min_y, width: max_x - min_x + 1, height: max_y - min_y + 1 })
184|}
185|
186|// Finally, identify the interior area after we've identified our border. 
187|fn find_interior(image: &image::RgbaImage, outer: &Rect) -> Option<Rect> {
188|    let width = image.width();
189|    let height = image.height();
190|
191|    let center_x = outer.x + outer.width / 2;
192|    let center_y = outer.y + outer.height / 2;
193|    if center_x >= width || center_y >= height { return None };
194|
195|    // We scan over from the left side of the rectangle to the right until we find where we're no longer at a border,
196|    // yielding our left inner bound.
197|    let inner_left = (outer.x..outer.x + outer.width).find(|&x| x < width && !is_border(*image.get_pixel(x, center_y)))?;
198|
199|    // We perform the same scan as before, but reverse it, meaning the first white pixel is now the furthest right, 
200|    // or hence this is our inner right border.
201|    let inner_right = (outer.x..outer.x + outer.width).rev().find(|&x| x < width && !is_border(*image.get_pixel(x, center_y)))?;
202|
203|    // Applying the same idea to the y-axis, we now scan from the top y all the way to the bottom y, 
204|    // and our first indice that is white is our inner border at the top.
205|    let inner_top = (outer.y..outer.y + outer.height).find(|&y| y < height && !is_border(*image.get_pixel(center_x, y)))?;
206|
207|    // Finally, to get the bottom border we do the same trick as we did with the right side and reverse the top search,
208|    // so that the first returned item is now the white pixel closest to the bottom.
209|    let inner_bottom = (outer.y..outer.y + outer.height).rev().find(|&y| y < height && !is_border(*image.get_pixel(center_x, y)))?;
210|
211|    Some(Rect {
212|        x: inner_left,
213|        y: inner_top,
214|        width: inner_right - inner_left + 1,
215|        height: inner_bottom - inner_top + 1
216|    })
